import { useMemo, useState } from 'react';

import Alert from '@mui/material/Alert';
import Box from '@mui/material/Box';
import Chip from '@mui/material/Chip';
import Divider from '@mui/material/Divider';
import Grid from '@mui/material/Grid';
import Skeleton from '@mui/material/Skeleton';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import ToggleButton from '@mui/material/ToggleButton';
import ToggleButtonGroup from '@mui/material/ToggleButtonGroup';
import Tooltip from '@mui/material/Tooltip';
import Typography from '@mui/material/Typography';
import { alpha } from '@mui/material/styles';
import {
  BarChart,
  LineChart,
  PieChart
} from '@mui/x-charts';

import AlertOutlined from '@ant-design/icons/AlertOutlined';
import CarOutlined from '@ant-design/icons/CarOutlined';
import DollarCircleOutlined from '@ant-design/icons/DollarCircleOutlined';
import FallOutlined from '@ant-design/icons/FallOutlined';
import HomeOutlined from '@ant-design/icons/HomeOutlined';
import RiseOutlined from '@ant-design/icons/RiseOutlined';
import TeamOutlined from '@ant-design/icons/TeamOutlined';
import ThunderboltOutlined from '@ant-design/icons/ThunderboltOutlined';

import { motion } from 'framer-motion';

import DashboardSectionCard from 'features/dashboard/components/DashboardSectionCard';
import KpiStatCard from 'features/dashboard/components/KpiStatCard';
import useDashboardAnalytics from 'features/dashboard/hooks/useDashboardAnalytics';
import MainCard from 'components/MainCard';
import { ErrorState } from 'components/common/PageFeedback';

const PRESET_OPTIONS = [
  { value: 'today', label: 'Hoy' },
  { value: 'last_7_days', label: '7 días' },
  { value: 'last_30_days', label: '30 días' },
  { value: 'this_month', label: 'Este mes' },
  { value: 'custom', label: 'Personalizado' }
];

function formatCurrency(value) {
  return Number(value || 0).toLocaleString('es-CL', {
    style: 'currency',
    currency: 'CLP',
    maximumFractionDigits: 0
  });
}

function formatNumber(value) {
  return Number(value || 0).toLocaleString('es-CL');
}

function formatPercent(value) {
  return `${Number(value || 0).toLocaleString('es-CL', { maximumFractionDigits: 1 })}%`;
}

function formatIsoDateLabel(value) {
  if (!value) return '-';
  const [year, month, day] = String(value).split('-');
  if (!year || !month || !day) return value;
  return `${day}/${month}`;
}

function healthColor(status) {
  if (status === 'green') return 'success';
  if (status === 'yellow') return 'warning';
  if (status === 'red') return 'error';
  return 'default';
}

function DashboardSkeleton() {
  return (
    <Stack sx={{ gap: 2.2 }}>
      <Skeleton variant="rounded" height={120} />
      <Grid container spacing={2}>
        {[...Array(6)].map((_, idx) => (
          <Grid key={idx} size={{ xs: 12, sm: 6, xl: 4 }}>
            <Skeleton variant="rounded" height={150} />
          </Grid>
        ))}
      </Grid>
      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 8 }}>
          <Skeleton variant="rounded" height={320} />
        </Grid>
        <Grid size={{ xs: 12, lg: 4 }}>
          <Skeleton variant="rounded" height={320} />
        </Grid>
      </Grid>
      <Skeleton variant="rounded" height={320} />
    </Stack>
  );
}

export default function DashboardPage() {
  const today = new Date();
  const defaultFrom = new Date(today);
  defaultFrom.setDate(defaultFrom.getDate() - 29);

  const [preset, setPreset] = useState('last_30_days');
  const [dateFrom, setDateFrom] = useState(defaultFrom.toISOString().slice(0, 10));
  const [dateTo, setDateTo] = useState(today.toISOString().slice(0, 10));
  const [parcelStatus, setParcelStatus] = useState('');
  const [parcelLetter, setParcelLetter] = useState('');

  const { data, error, isLoading, isRefreshing } = useDashboardAnalytics({
    preset,
    dateFrom,
    dateTo,
    parcelStatus,
    parcelLetter
  });

  const kpis = data?.kpis || {};
  const charts = data?.charts || {};
  const smart = data?.smart_indicators || {};
  const alerts = data?.alerts || [];
  const anomalies = data?.anomalies || [];
  const insights = data?.insights || [];
  const rankings = data?.rankings?.critical_parcels || [];

  const cardRows = useMemo(
    () => [
      {
        title: 'Parcelas totales',
        value: formatNumber(kpis.parcels_total),
        helper: `${formatNumber(kpis.parcels_active)} activas`,
        status: 'neutral',
        accent: '#2563EB',
        icon: <HomeOutlined />
      },
      {
        title: 'Parcelas morosas',
        value: formatNumber(kpis.parcels_in_arrears),
        helper: `Morosidad: ${formatPercent(kpis.arrears_rate)}`,
        status: kpis.arrears_rate >= 30 ? 'red' : kpis.arrears_rate >= 18 ? 'yellow' : 'green',
        accent: '#DC2626',
        icon: <AlertOutlined />
      },
      {
        title: 'Residentes totales',
        value: formatNumber(kpis.residents_total),
        helper: `Ratio parcela: ${smart.residents_per_parcel_ratio ?? 0}`,
        status: 'green',
        accent: '#0284C7',
        icon: <TeamOutlined />
      },
      {
        title: 'Vehículos totales',
        value: formatNumber(kpis.vehicles_total),
        helper: `Ratio residente: ${smart.vehicles_per_resident_ratio ?? 0}`,
        status: 'green',
        accent: '#0F766E',
        icon: <CarOutlined />
      },
      {
        title: 'Pagos de hoy',
        value: formatNumber(kpis.payments_today),
        helper: `Ticket promedio: ${formatCurrency(smart.average_payment_ticket)}`,
        status: kpis.payments_today > 0 ? 'green' : 'yellow',
        accent: '#15803D',
        icon: <RiseOutlined />
      },
      {
        title: 'Recaudado hoy',
        value: formatCurrency(kpis.collected_today),
        helper: `Var. día: ${formatPercent(smart.collection_variation_day_pct)}`,
        status: smart.collection_variation_day_pct < -20 ? 'red' : smart.collection_variation_day_pct < -5 ? 'yellow' : 'green',
        accent: '#16A34A',
        icon: <DollarCircleOutlined />
      },
      {
        title: 'Recaudado este mes',
        value: formatCurrency(kpis.collected_month),
        helper: `Proyección: ${formatCurrency(smart.projected_month_collection)}`,
        status: smart.collection_variation_month_pct < 0 ? 'yellow' : 'green',
        accent: '#059669',
        icon: <RiseOutlined />
      },
      {
        title: 'Pendiente por cobrar',
        value: formatCurrency(kpis.pending_total),
        helper: `Promedio por morosa: ${formatCurrency(smart.average_debt_per_morose_parcel)}`,
        status: kpis.pending_total > 0 ? 'red' : 'green',
        accent: '#B91C1C',
        icon: <FallOutlined />
      },
      {
        title: 'Incidencias abiertas',
        value: formatNumber(kpis.open_incidents),
        helper: `${formatNumber(kpis.active_cuts)} cortes activos`,
        status: kpis.open_incidents >= 20 ? 'red' : kpis.open_incidents >= 8 ? 'yellow' : 'green',
        accent: '#B45309',
        icon: <ThunderboltOutlined />
      },
      {
        title: 'Visitas del día',
        value: formatNumber(kpis.visits_today),
        helper: 'Actividad operativa en terreno',
        status: 'neutral',
        accent: '#334155',
        icon: <TeamOutlined />
      },
      {
        title: 'Ingresos del día',
        value: formatCurrency(kpis.income_today),
        helper: 'Movimientos confirmados',
        status: 'green',
        accent: '#166534',
        icon: <RiseOutlined />
      },
      {
        title: 'Egresos del día',
        value: formatCurrency(kpis.expense_today),
        helper: 'Costo operativo diario',
        status: kpis.expense_today > kpis.income_today ? 'red' : 'yellow',
        accent: '#92400E',
        icon: <FallOutlined />
      }
    ],
    [kpis, smart]
  );

  if (isLoading && !data) return <DashboardSkeleton />;
  if (error) return <ErrorState message="No fue posible cargar el dashboard analítico." />;

  const arrearsSeries = charts.arrears_daily || [];
  const collectionSeries = charts.collection_daily || [];
  const residentsSeries = charts.new_residents_period || [];
  const vehiclesSeries = charts.vehicles_registered_period || [];
  const parcelsStatusComparison = charts.parcels_status_comparison || [];
  const paymentStatusDistribution = charts.payment_status_distribution || [];
  const monthlyCollection = charts.monthly_collection_trend || [];
  const topParcelsDebt = charts.top_parcels_debt || [];
  const topMonthsMorosity = charts.top_months_morosity || [];
  const operationsRecent = charts.operations_recent || [];

  return (
    <Stack sx={{ gap: 2.2 }}>
      <MainCard
        boxShadow
        contentSX={{ p: { xs: 2.1, md: 2.8 } }}
        sx={{
          borderColor: alpha('#1D4ED8', 0.24),
          background: 'linear-gradient(135deg, rgba(29,78,216,0.12) 0%, rgba(14,116,144,0.10) 45%, #FFFFFF 100%)'
        }}
      >
        <Stack sx={{ gap: 2 }}>
          <Stack direction={{ xs: 'column', xl: 'row' }} sx={{ justifyContent: 'space-between', gap: 2 }}>
            <Box>
              <Typography variant="h2" sx={{ fontSize: { xs: '1.65rem', md: '2rem' } }}>
                Panel Ejecutivo Operacional
              </Typography>
              <Typography variant="body1" color="text.secondary" sx={{ mt: 0.8, maxWidth: 820 }}>
                Visualización inteligente para detectar morosidad, evolución de recaudación, actividad operativa y focos críticos por parcela.
              </Typography>
            </Box>
            <Stack direction="row" sx={{ alignItems: 'center', gap: 1 }}>
              <Chip
                label={`Semáforo: ${(smart.health_semaphore || 'neutral').toUpperCase()}`}
                color={healthColor(smart.health_semaphore)}
                variant="filled"
              />
              {isRefreshing ? <Chip size="small" label="Actualizando..." variant="outlined" /> : null}
            </Stack>
          </Stack>

          <Stack direction={{ xs: 'column', lg: 'row' }} sx={{ gap: 1.2, flexWrap: 'wrap' }}>
            <ToggleButtonGroup
              color="primary"
              exclusive
              value={preset}
              onChange={(_, value) => {
                if (value) setPreset(value);
              }}
              size="small"
            >
              {PRESET_OPTIONS.map((option) => (
                <ToggleButton key={option.value} value={option.value}>
                  {option.label}
                </ToggleButton>
              ))}
            </ToggleButtonGroup>

            <TextField
              size="small"
              select
              SelectProps={{ native: true }}
              value={parcelStatus}
              onChange={(event) => setParcelStatus(event.target.value)}
              label="Estado parcela"
              sx={{ minWidth: 170 }}
            >
              <option value="">Todos</option>
              <option value="ACTIVA">Activa</option>
              <option value="INACTIVA">Inactiva</option>
              <option value="SUSPENDIDA">Suspendida</option>
            </TextField>

            <TextField
              size="small"
              label="Sector (letra lote)"
              value={parcelLetter}
              onChange={(event) => setParcelLetter(event.target.value.toUpperCase())}
              placeholder="A, B, N..."
              sx={{ minWidth: 170 }}
            />

            {preset === 'custom' ? (
              <>
                <TextField size="small" type="date" label="Desde" value={dateFrom} onChange={(event) => setDateFrom(event.target.value)} InputLabelProps={{ shrink: true }} />
                <TextField size="small" type="date" label="Hasta" value={dateTo} onChange={(event) => setDateTo(event.target.value)} InputLabelProps={{ shrink: true }} />
              </>
            ) : null}
          </Stack>
        </Stack>
      </MainCard>

      <Grid container spacing={2}>
        {cardRows.map((item, index) => (
          <Grid key={item.title} size={{ xs: 12, sm: 6, xl: 3 }}>
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.24, delay: index * 0.03 }}>
              <KpiStatCard {...item} />
            </motion.div>
          </Grid>
        ))}
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, xl: 7 }}>
          <DashboardSectionCard title="Evolución diaria de parcelas morosas" subtitle="Tendencia reconstruida con eventos de deuda abiertos/cerrados.">
            {arrearsSeries.length ? (
              <LineChart
                height={300}
                xAxis={[{ scaleType: 'point', data: arrearsSeries.map((item) => formatIsoDateLabel(item.date)) }]}
                series={[{ data: arrearsSeries.map((item) => item.count), label: 'Parcelas morosas', color: '#DC2626', showMark: false, curve: 'monotoneX' }]}
                margin={{ top: 20, right: 20, left: 30, bottom: 30 }}
              />
            ) : (
              <Alert severity="info">Sin datos de morosidad para el rango seleccionado.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, xl: 5 }}>
          <DashboardSectionCard title="Comparativa al día vs morosas" subtitle="Distribución global de estado de pago por parcela." sx={{ height: '100%' }}>
            {parcelsStatusComparison.length ? (
              <PieChart
                height={300}
                series={[
                  {
                    innerRadius: 70,
                    outerRadius: 110,
                    cornerRadius: 8,
                    data: parcelsStatusComparison.map((item, idx) => ({ id: idx, value: item.value, label: item.label }))
                  }
                ]}
                colors={['#16A34A', '#DC2626']}
              />
            ) : (
              <Alert severity="info">Sin datos para comparar estado de parcelas.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, xl: 7 }}>
          <DashboardSectionCard title="Evolución diaria de pagos y recaudación" subtitle="Cantidad de pagos diarios y monto total recaudado por día.">
            {collectionSeries.length ? (
              <LineChart
                height={320}
                xAxis={[{ scaleType: 'point', data: collectionSeries.map((item) => formatIsoDateLabel(item.date)) }]}
                series={[
                  { data: collectionSeries.map((item) => item.amount), label: 'Recaudación (CLP)', color: '#0EA5E9', showMark: false, curve: 'monotoneX' },
                  { data: collectionSeries.map((item) => item.payments), label: 'Pagos', color: '#1D4ED8', showMark: false, curve: 'linear' }
                ]}
                margin={{ top: 24, right: 20, left: 30, bottom: 30 }}
              />
            ) : (
              <Alert severity="info">No hay pagos en el rango consultado.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, xl: 5 }}>
          <DashboardSectionCard title="Distribución de estados de pago" subtitle="Composición de deuda por estado actual." sx={{ height: '100%' }}>
            {paymentStatusDistribution.length ? (
              <PieChart
                height={320}
                series={[
                  {
                    innerRadius: 60,
                    outerRadius: 112,
                    data: paymentStatusDistribution.map((item, idx) => ({ id: idx, value: item.value, label: item.label }))
                  }
                ]}
                colors={['#B91C1C', '#F59E0B', '#16A34A', '#64748B', '#0EA5E9']}
              />
            ) : (
              <Alert severity="info">Aún no existen registros de estado de pago.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 6 }}>
          <DashboardSectionCard title="Nuevos residentes por período">
            {residentsSeries.length ? (
              <BarChart
                height={300}
                xAxis={[{ scaleType: 'band', data: residentsSeries.map((item) => formatIsoDateLabel(item.date || item.week || item.month)) }]}
                series={[{ data: residentsSeries.map((item) => item.count), label: 'Residentes', color: '#2563EB' }]}
                margin={{ top: 20, right: 10, left: 10, bottom: 32 }}
                borderRadius={7}
              />
            ) : (
              <Alert severity="info">No hay altas de residentes en el período.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, lg: 6 }}>
          <DashboardSectionCard title="Vehículos registrados por período">
            {vehiclesSeries.length ? (
              <BarChart
                height={300}
                xAxis={[{ scaleType: 'band', data: vehiclesSeries.map((item) => formatIsoDateLabel(item.date || item.week || item.month)) }]}
                series={[{ data: vehiclesSeries.map((item) => item.count), label: 'Vehículos', color: '#0F766E' }]}
                margin={{ top: 20, right: 10, left: 10, bottom: 32 }}
                borderRadius={7}
              />
            ) : (
              <Alert severity="info">No hay nuevos vehículos en el período.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, xl: 6 }}>
          <DashboardSectionCard title="Tendencia mensual de recaudación" subtitle="Últimos 12 meses de ingresos confirmados.">
            {monthlyCollection.length ? (
              <BarChart
                height={310}
                xAxis={[{ scaleType: 'band', data: monthlyCollection.map((item) => item.month) }]}
                series={[{ data: monthlyCollection.map((item) => item.amount), label: 'CLP', color: '#0284C7' }]}
                margin={{ top: 20, right: 20, left: 20, bottom: 40 }}
                borderRadius={7}
              />
            ) : (
              <Alert severity="info">No existen movimientos de ingresos para esta serie.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, xl: 6 }}>
          <DashboardSectionCard title="Top parcelas con mayor deuda" subtitle="Concentración de deuda pendiente por parcela.">
            {topParcelsDebt.length ? (
              <BarChart
                height={310}
                xAxis={[{ scaleType: 'band', data: topParcelsDebt.map((item) => item.parcel_code) }]}
                series={[{ data: topParcelsDebt.map((item) => item.debt), label: 'Deuda CLP', color: '#DC2626' }]}
                margin={{ top: 20, right: 10, left: 16, bottom: 52 }}
                borderRadius={7}
              />
            ) : (
              <Alert severity="info">No hay deuda pendiente para rankear.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 6 }}>
          <DashboardSectionCard title="Top meses con más morosidad">
            {topMonthsMorosity.length ? (
              <BarChart
                height={300}
                xAxis={[{ scaleType: 'band', data: topMonthsMorosity.map((item) => item.month) }]}
                series={[{ data: topMonthsMorosity.map((item) => item.count), label: 'Parcelas morosas', color: '#B91C1C' }]}
                margin={{ top: 20, right: 10, left: 16, bottom: 34 }}
                borderRadius={7}
              />
            ) : (
              <Alert severity="info">Aún no hay historial suficiente para detectar meses críticos.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, lg: 6 }}>
          <DashboardSectionCard title="Actividad operativa reciente" subtitle="Eventos de acceso, visitas, anotaciones, finanzas y vuelos.">
            {operationsRecent.length ? (
              <Stack sx={{ gap: 1 }}>
                {operationsRecent.map((event, idx) => (
                  <Stack
                    key={`${event.type}-${idx}`}
                    direction="row"
                    sx={{
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      gap: 1,
                      p: 1.1,
                      borderRadius: 1.5,
                      border: '1px solid',
                      borderColor: 'divider',
                      bgcolor: event.severity === 'critical' ? alpha('#DC2626', 0.08) : alpha('#1E40AF', 0.05)
                    }}
                  >
                    <Box>
                      <Typography variant="subtitle2">{event.title}</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {event.detail}
                      </Typography>
                    </Box>
                    <Tooltip title={event.timestamp}>
                      <Chip size="small" label={event.type} color={event.severity === 'critical' ? 'error' : event.severity === 'warning' ? 'warning' : 'default'} />
                    </Tooltip>
                  </Stack>
                ))}
              </Stack>
            ) : (
              <Alert severity="info">No hay actividad reciente para mostrar.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, xl: 4 }}>
          <DashboardSectionCard title="Alertas automáticas">
            {alerts.length ? (
              <Stack sx={{ gap: 1 }}>
                {alerts.map((alert, idx) => (
                  <Alert key={`${alert.title}-${idx}`} severity={alert.level === 'critical' ? 'error' : 'warning'}>
                    <strong>{alert.title}:</strong> {alert.message}
                  </Alert>
                ))}
              </Stack>
            ) : (
              <Alert severity="success">Sin alertas críticas en este corte.</Alert>
            )}

            {anomalies.length ? (
              <>
                <Divider sx={{ my: 1.2 }} />
                <Typography variant="subtitle2">Anomalías detectadas</Typography>
                <Stack sx={{ gap: 0.8 }}>
                  {anomalies.map((item, idx) => (
                    <Chip key={`${item.type}-${idx}`} label={item.description} color={item.severity === 'high' ? 'error' : 'warning'} sx={{ justifyContent: 'flex-start' }} />
                  ))}
                </Stack>
              </>
            ) : null}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, xl: 4 }}>
          <DashboardSectionCard title="Insights automáticos">
            {insights.length ? (
              <Stack sx={{ gap: 1 }}>
                {insights.map((text, idx) => (
                  <Box key={`insight-${idx}`} sx={{ p: 1.1, borderRadius: 1.5, border: '1px solid', borderColor: 'divider', bgcolor: 'grey.50' }}>
                    <Typography variant="body2">{text}</Typography>
                  </Box>
                ))}
              </Stack>
            ) : (
              <Alert severity="info">Sin insights disponibles para el rango seleccionado.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>

        <Grid size={{ xs: 12, xl: 4 }}>
          <DashboardSectionCard title="Ranking de parcelas críticas" subtitle="Semáforo combinado por deuda, cortes y objetivos abiertos.">
            {rankings.length ? (
              <Stack sx={{ gap: 1 }}>
                {rankings.slice(0, 8).map((item) => (
                  <Stack
                    key={item.parcel_id}
                    direction="row"
                    sx={{
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      gap: 1,
                      p: 1,
                      borderRadius: 1.5,
                      border: '1px solid',
                      borderColor: 'divider'
                    }}
                  >
                    <Box>
                      <Typography variant="subtitle2">{item.parcel_code}</Typography>
                      <Typography variant="caption" color="text.secondary">
                        Deuda {formatCurrency(item.pending_debt)} · Cortes {item.active_cuts} · Objetivos {item.open_objectives}
                      </Typography>
                    </Box>
                    <Chip
                      size="small"
                      label={`Score ${item.critical_score}`}
                      color={item.semaphore === 'red' ? 'error' : item.semaphore === 'yellow' ? 'warning' : 'success'}
                    />
                  </Stack>
                ))}
              </Stack>
            ) : (
              <Alert severity="success">No hay parcelas críticas en este momento.</Alert>
            )}
          </DashboardSectionCard>
        </Grid>
      </Grid>
    </Stack>
  );
}
