import { useMemo } from 'react';

import useSWR from 'swr';

import apiClient from 'lib/http/apiClient';
import API_PATHS from 'lib/http/apiPaths';

const fetchDashboard = async ([url, params]) => {
  const response = await apiClient.get(url, { params });
  return response.data;
};

export default function useDashboardAnalytics(filters) {
  const params = useMemo(
    () => ({
      preset: filters.preset,
      date_from: filters.preset === 'custom' ? filters.dateFrom || undefined : undefined,
      date_to: filters.preset === 'custom' ? filters.dateTo || undefined : undefined,
      parcel_status: filters.parcelStatus || undefined,
      parcel_letter: filters.parcelLetter || undefined
    }),
    [filters.dateFrom, filters.dateTo, filters.parcelLetter, filters.parcelStatus, filters.preset]
  );

  const { data, error, isLoading, isValidating, mutate } = useSWR([API_PATHS.dashboardSummary, params], fetchDashboard, {
    revalidateOnFocus: false,
    keepPreviousData: true
  });

  return {
    data,
    error,
    isLoading,
    isRefreshing: isValidating,
    reload: mutate
  };
}
