import PropTypes from 'prop-types';

import Box from '@mui/material/Box';
import Chip from '@mui/material/Chip';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';
import { alpha } from '@mui/material/styles';

import MainCard from 'components/MainCard';

const STATUS_COLORS = {
  green: '#15803D',
  yellow: '#B45309',
  red: '#B91C1C',
  neutral: '#475569'
};

export default function KpiStatCard({ title, value, helper, icon, status = 'neutral', accent = '#2563EB' }) {
  const statusColor = STATUS_COLORS[status] || STATUS_COLORS.neutral;
  return (
    <MainCard
      boxShadow
      contentSX={{ p: 2.25 }}
      sx={{
        height: '100%',
        borderColor: alpha(accent, 0.26),
        background: `linear-gradient(160deg, ${alpha(accent, 0.12)} 0%, #FFFFFF 72%)`
      }}
    >
      <Stack direction="row" sx={{ justifyContent: 'space-between', gap: 1.2 }}>
        <Stack sx={{ gap: 0.4 }}>
          <Typography variant="caption" color="text.secondary">
            {title}
          </Typography>
          <Typography variant="h3" sx={{ fontSize: { xs: '1.45rem', md: '1.7rem' } }}>
            {value}
          </Typography>
          {helper ? (
            <Typography variant="body2" color="text.secondary">
              {helper}
            </Typography>
          ) : null}
          <Chip
            size="small"
            label={status.toUpperCase()}
            sx={{
              width: 'fit-content',
              bgcolor: alpha(statusColor, 0.12),
              color: statusColor,
              fontWeight: 700
            }}
          />
        </Stack>
        <Box
          sx={{
            minWidth: 38,
            minHeight: 38,
            borderRadius: 2,
            display: 'grid',
            placeItems: 'center',
            bgcolor: alpha(accent, 0.16),
            color: accent
          }}
        >
          {icon}
        </Box>
      </Stack>
    </MainCard>
  );
}

KpiStatCard.propTypes = {
  title: PropTypes.string.isRequired,
  value: PropTypes.oneOfType([PropTypes.string, PropTypes.number]).isRequired,
  helper: PropTypes.string,
  icon: PropTypes.node,
  status: PropTypes.oneOf(['green', 'yellow', 'red', 'neutral']),
  accent: PropTypes.string
};
